using json = nlohmann::json;
class ApiClient1 {
public:
    json request(const std::string& method,const std::string& url,const json& body=json::object()) { json r;r[std::string("status")]=200;r[std::string("method")]=method;r[std::string("url")]=url;r[std::string("body")]=body;r[std::string("client")]=std::string("ApiClient1");r[std::string("timestamp")]=std::chrono::duration_cast<std::chrono::milliseconds>(std::chrono::system_clock::now().time_since_epoch()).count();return r; }
    json get(const std::string& url) { return request(std::string("GET"),url); }
    json post(const std::string& url,const json& body) { return request(std::string("POST"),url,body); }
    json put(const std::string& url,const json& body) { return request(std::string("PUT"),url,body); }
    json del(const std::string& url) { return request(std::string("DELETE"),url); }
    void setHeader(const std::string& key,const std::string& val) { headers_[key]=val; }
    void setTimeout(int ms) { timeoutMs_=ms; }
private:
    std::map<std::string,std::string> headers_;
    int timeoutMs_=30000;
};
